mapper.select:
select co.course_id as course_id , co.title as title , us.name as name , ct.start_time , ct.end_time , cc.class_name as class_name , cc.people_limit , IFNULL(sc.cnt, 0) as stu_num , co.start_date , co.end_date , co.time_code from course co inner join tb_userinfo us on co.professor = us.loginID inner join course_time ct on ct.time_code = co.time_code inner join course_class cc on cc.class_id = co.class_id left join ( select course_id, count(course_id) cnt from student_course where stu_cou_sta_code = 0 group by course_id ) sc on co.course_id = sc.course_id
AND co.course_id LIKE CONCAT('%', #{searchWord}, '%')
${searchKey} LIKE CONCAT('%', #{searchWord}, '%')
AND co.start_date >= #{startDate}
AND co.end_date <= #{endDate}
AND co.cos_sta_code = 1 AND co.course_isDeleted = 0
order by co.course_id limit #{start}, #{end}

