mapper.select:
select count(sc.stu_cou_id)
#         , ats.status
from student_course sc



    sc.loginID = #{loginID}

        AND sc.stu_cou_sta_code = #{searchKey}


        AND co.start_date  >=  #{startDate}


        AND co.end_date  <=  #{endDate}


order by sc.stu_cou_sta_code asc

SELECT co.course_id, co.title, us.name, cc.class_name, scs.name as scs_name, ct.start_time, ct.end_time, co.start_date, co.end_date, co.time_code FROM student_course sc INNER JOIN course co ON sc.course_id = co.course_id INNER JOIN tb_userinfo us ON co.professor = us.loginID INNER JOIN course_class cc ON co.class_id = cc.class_id INNER JOIN student_course_status scs ON sc.stu_cou_sta_code = scs.stu_cou_sta_code INNER JOIN course_time ct ON co.time_code = ct.time_code WHERE sc.loginID = #{loginID}
AND sc.stu_cou_sta_code = #{searchKey}
ORDER BY sc.stu_cou_sta_code ASC LIMIT #{start}, #{pageSize}

SELECT sc.course_id, co.title, us.name AS professior, sub_us.name AS sub_prof, cc.class_name, us.phone, us.email, scs.name AS stu_cou_sta_name, co.start_date, co.end_date, co.time_code, ct.start_time, ct.end_time, att.attendance, att.absen_sick, att.tard_levEarly, co.content, co.notice, co.plan,
IFNULL(cnt.cnt, 0) as stu_num, cc.people_limit
FROM student_course sc INNER JOIN course co ON sc.course_id = co.course_id INNER JOIN tb_userinfo us ON us.loginID = co.professor INNER JOIN tb_userinfo sub_us ON sub_us.loginID = co.sub_prof INNER JOIN course_class cc ON co.class_id = cc.class_id INNER JOIN student_course_status scs ON sc.stu_cou_sta_code = scs.stu_cou_sta_code INNER JOIN course_time ct ON co.time_code = ct.time_code LEFT JOIN ( SELECT course_id, loginID, SUM(CASE WHEN att_sta_code = 1 THEN 1 ELSE 0 END) AS attendance, SUM(CASE WHEN att_sta_code = 0 THEN 1 ELSE 0 END) AS absen_sick, SUM(CASE WHEN att_sta_code IN (3,4,5) THEN 1 ELSE 0 END) AS tard_levEarly FROM course_attendance WHERE loginID = #{loginID} GROUP BY course_id, loginID ) att ON att.course_id = co.course_id AND att.loginID = sc.loginID left join ( select course_id, count(course_id) cnt from student_course where course_id = #{course_id} and stu_cou_sta_code = 0 group by course_id ) cnt on sc.course_id = cnt.course_id WHERE sc.loginID = #{loginID} AND sc.course_id = #{course_id}

SELECT DATE_FORMAT(ca.date, '%Y-%m-%d') AS att_date,
       ca.att_sta_code
FROM course_attendance ca
WHERE ca.loginID = #{loginID}
  AND ca.course_id = #{course_id}
  AND YEAR(ca.date) = #{year}
  AND MONTH(ca.date) = #{month}
ORDER BY ca.date

SELECT COUNT(1)
FROM student_course
WHERE loginID = #{loginID}
AND course_id = #{course_id}
AND stu_cou_sta_code = 0

SELECT COUNT(1)
FROM student_course
WHERE loginID = #{loginID}
  AND course_id = #{course_id}
  AND stu_cou_sta_code = 1
